#include <iostream>
#include <string>
#include <sstream>

// Wallet class will be inserted here

int main() {
    Wallet wallet;
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        std::string command;
        ss >> command;
        if (command == "deposit") {
            int amount;
            ss >> amount;
            wallet.deposit(amount);
        } else if (command == "withdraw") {
            int amount;
            ss >> amount;
            wallet.withdraw(amount);
        } else if (command == "balance") {
            std::cout << "Balance: " << wallet.getBalance() << std::endl;
        }
    }
    return 0;
}
